import os
TMPL = 'iipms_app/templates/iipms_app'
os.makedirs('iipms_app/templatetags', exist_ok=True)
open('iipms_app/templatetags/__init__.py', 'w').write('')
open('iipms_app/templatetags/custom_filters.py', 'w').write('from django import template\nregister = template.Library()\n\n@register.filter\ndef split_comma(value):\n    if not value:\n        return []\n    return [s.strip() for s in str(value).split(\',\') if s.strip()]\n\n@register.filter\ndef get_profile(profiles, user_id):\n    for p in profiles:\n        if p.user_id == user_id:\n            return p\n    return None\n')
